To achieve the functionality of creating a polyline when a user clicks on one point and then on another point from the geojson file, you can listen for click events on the circle markers and store the coordinates of the clicked points. Once two points have been clicked, you can then create a polyline between them.

Here is an updated version of your code with the added functionality:

```javascript
const map = L.map('map').setView([54.2231637,-1.9381623], 6);
let clickedPoints = [];

// Function to create circle markers with click functionality
function createCircleMarkers(geojson) {
  return L.geoJSON(geojson, {
    pointToLayer: function (feature, latlng) {
      const circleMarker = L.circleMarker(latlng, {
        radius: 4,
        fillColor: '#ff7800',
        color: '#000',
        weight: 0.2,
        opacity: 1,
        fillOpacity: 0.8
      });

      // Bind a popup with city name on mouseover
      circleMarker.on('mouseover', function () {
        this.bindPopup(feature.properties.city).openPopup();
      });

      // Add click event listener to store clicked point coordinates
      circleMarker.on('click', function (e) {
        clickedPoints.push(e.latlng);

